bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const {
    // Self-transition is always valid
    if (from == to) {
        return true;
    }

    // Define valid transitions based on state flow
    switch (from) {
        case kDeviceStateUnknown:
            // From unknown, can only go to starting
            return to == kDeviceStateStarting;

        case kDeviceStateStarting:
            // From starting, can go to wifi configuring or idle
            return (to == kDeviceStateWifiConfiguring) || (to == kDeviceStateIdle);

        case kDeviceStateWifiConfiguring:
            // From wifi configuring, can go to idle or connecting
            return (to == kDeviceStateIdle) || (to == kDeviceStateConnecting);

        case kDeviceStateIdle:
            // From idle, can go to connecting or listening or speaking
            return (to == kDeviceStateConnecting) || 
                   (to == kDeviceStateListening) || 
                   (to == kDeviceStateSpeaking) ||
                   (to == kDeviceStateUpgrading) ||
                   (to == kDeviceStateActivating);

        case kDeviceStateConnecting:
            // From connecting, can go to idle or listening
            return (to == kDeviceStateIdle) || (to == kDeviceStateListening);

        case kDeviceStateListening:
            // From listening, can go to speaking or idle
            return (to == kDeviceStateSpeaking) || (to == kDeviceStateIdle);

        case kDeviceStateSpeaking:
            // From speaking, can go to listening or idle
            return (to == kDeviceStateListening) || (to == kDeviceStateIdle);

        case kDeviceStateUpgrading:
            // From upgrading, can go to activating or fatal error
            return (to == kDeviceStateActivating) || (to == kDeviceStateFatalError);

        case kDeviceStateActivating:
            // From activating, can go to idle or fatal error
            return (to == kDeviceStateIdle) || (to == kDeviceStateFatalError);

        case kDeviceStateAudioTesting:
            // From audio testing, can go to idle or fatal error
            return (to == kDeviceStateIdle) || (to == kDeviceStateFatalError);

        case kDeviceStateFatalError:
            // From fatal error, can only go to unknown (reset)
            return to == kDeviceStateUnknown;

        default:
            // Invalid from state
            return false;
    }
}

