        has_new_version_ = IsNewVersionAvailable(current_version, firmware_version_);
    }

    // Parse activation challenge if present
    cJSON *activation_obj = cJSON_GetObjectItem(json, "activation");
    if (activation_obj != NULL && cJSON_IsObject(activation_obj)) {
        cJSON *challenge_obj = cJSON_GetObjectItem(activation_obj, "challenge");
        if (challenge_obj != NULL && cJSON_IsString(challenge_obj)) {
            activation_challenge_ = cJSON_GetStringValue(challenge_obj);
            has_activation_challenge_ = true;
            ESP_LOGI(TAG, "Activation challenge received: %s", activation_challenge_.c_str());
        }

        cJSON *message_obj = cJSON_GetObjectItem(activation_obj, "message");
        if (message_obj != NULL && cJSON_IsString(message_obj)) {
            activation_message_ = cJSON_GetStringValue(message_obj);
            ESP_LOGI(TAG, "Activation message: %s", activation_message_.c_str());
        }

