        if (code_obj != NULL && cJSON_IsString(code_obj)) {
            activation_code_ = cJSON_GetStringValue(code_obj);
            has_activation_code_ = true;
            ESP_LOGI(TAG, "Activation code: %s", activation_code_.c_str());
        }
    }

    // Parse MQTT configuration if present
    cJSON *mqtt_obj = cJSON_GetObjectItem(json, "mqtt");
    if (mqtt_obj != NULL && cJSON_IsObject(mqtt_obj)) {
        has_mqtt_config_ = true;
        ESP_LOGI(TAG, "MQTT configuration present in response");
    }

    // Parse WebSocket configuration if present
    cJSON *websocket_obj = cJSON_GetObjectItem(json, "websocket");
    if (websocket_obj != NULL && cJSON_IsObject(websocket_obj)) {
        has_websocket_config_ = true;
        ESP_LOGI(TAG, "WebSocket configuration present in response");
    }

    // Parse server time if present
    cJSON *server_time_obj = cJSON_GetObjectItem(json, "server_time");
    if (server_time_obj != NULL && cJSON_IsNumber(server_time_obj)) {
        has_server_time_ = true;
        ESP_LOGI(TAG, "Server time present in response: %ld", (long)server_time_obj->valuedouble);
    }

    cJSON_Delete(json);

    ESP_LOGI(TAG, "Version check completed successfully");
    return ESP_OK;
}

