esp_err_t Ota::Activate()
{
    if (!has_activation_challenge_)
    {
        ESP_LOGW(TAG, "No activation challenge available");
        return ESP_ERR_INVALID_STATE;
    }

    // Construct activation URL from the check version URL
    std::string url = GetCheckVersionUrl();
    if (url.length() < 10)
    {
        ESP_LOGE(TAG, "Activation URL is not properly set");
        return ESP_ERR_INVALID_ARG;
    }

    // Append "/activate" to the base URL
    if (url.back() != '/')
    {
        url += '/';
    }
    url += "activate";

    auto http = SetupHttp();

    // Prepare the activation payload
    std::string payload = GetActivationPayload();
    http->SetContent(std::move(payload));

    // Open HTTP connection with POST method
    if (!http->Open("POST", url))
    {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for activation, code=0x%x", last_error);
        return last_error;
    }

    // Check the status code
    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to activate, status code: %d", status_code);
        return status_code;
    }

    // Read response if needed
    std::string response = http->ReadAll();
    http->Close();

    // Parse response to check activation result
    cJSON *root = cJSON_Parse(response.c_str());
    if (root == NULL)
    {
        ESP_LOGE(TAG, "Failed to parse activation response JSON");
        return ESP_ERR_INVALID_RESPONSE;
    }

    // Check if activation was successful by looking for success indicators
    cJSON *success = cJSON_GetObjectItem(root, "success");
    if (cJSON_IsBool(success))
    {
        if (!cJSON_IsTrue(success))
        {
            cJSON *error = cJSON_GetObjectItem(root, "error");
            if (cJSON_IsString(error))
            {
                ESP_LOGE(TAG, "Activation failed: %s", error->valuestring);
            }
            else
            {
                ESP_LOGE(TAG, "Activation failed");
            }
            cJSON_Delete(root);
            return ESP_FAIL;
        }
    }

    // If we don't have explicit success field, assume success if status is 200
    // and we got a valid response

    cJSON_Delete(root);

    ESP_LOGI(TAG, "Activation successful");
    return ESP_OK;
}

