esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait) {
    // Get initial tick count
    TickType_t start_tick = xTaskGetTickCount();

    // Wait for the specified time interval
    vTaskDelay(xTicksToWait);

    // Get end tick count
    TickType_t end_tick = xTaskGetTickCount();

    // Calculate elapsed time in ticks
    TickType_t elapsed_ticks = end_tick - start_tick;

    // Convert ticks to milliseconds
    uint32_t elapsed_ms = (elapsed_ticks * portTICK_PERIOD_MS);

    // Get current task list
    char buffer[1000];
    vTaskList(buffer);

    // Display header
    ESP_LOGI(TAG, "CPU Usage Report (over %lu ms):", elapsed_ms);
    ESP_LOGI(TAG, "Task Name           Status    CPU Usage");
    ESP_LOGI(TAG, "----------------------------------------");

    // Parse and display task information
    char *line = strtok(buffer, "\n");
    while (line != NULL) {
        // Skip empty lines
        if (strlen(line) > 0 && line[0] != '\0') {
            // Display the line as-is for now
            // In a full implementation, we would parse the fields and calculate CPU usage
            ESP_LOGI(TAG, "%s", line);
        }
        line = strtok(NULL, "\n");
    }

    ESP_LOGI(TAG, "----------------------------------------");
    ESP_LOGI(TAG, "Measurement completed over %lu ms", elapsed_ms);

    return ESP_OK;
}

