void AudioService::AudioInputTask() {
    ESP_LOGI(TAG, "Audio input task started");

    // Define audio frame size based on codec configuration
    int frame_size = codec_->input_channels() * codec_->input_sample_rate() * OPUS_FRAME_DURATION_MS / 1000;

    while (!service_stopped_) {
        // Check which processing paths are active
        EventBits_t bits = xEventGroupGetBits(event_group_);
        bool is_testing = bits & AS_EVENT_AUDIO_TESTING_RUNNING;
        bool is_wake_word_running = bits & AS_EVENT_WAKE_WORD_RUNNING;
        bool is_audio_processor_running = bits & AS_EVENT_AUDIO_PROCESSOR_RUNNING;

        // Read audio data
        std::vector<int16_t> audio_frame(frame_size);
        if (!ReadAudioData(audio_frame, codec_->input_sample_rate(), frame_size / codec_->input_channels())) {
            ESP_LOGW(TAG, "Failed to read audio data, retrying...");
            vTaskDelay(pdMS_TO_TICKS(10));
            continue;
        }

        // Process based on current state
        if (is_testing) {
            // For audio testing, just push to testing queue
            auto task = std::make_unique<AudioTask>();
            task->type = kAudioTaskTypeEncodeToTestingQueue;
            task->pcm = std::move(audio_frame);

            std::lock_guard<std::mutex> lock(audio_queue_mutex_);
            if (audio_testing_queue_.size() < MAX_TESTING_TASKS_IN_QUEUE) {
                audio_testing_queue_.push_back(std::move(task));
                audio_queue_cv_.notify_all();
            }
        } 
        else if (is_wake_word_running) {
            // For wake word detection, pass to wake word processor
            if (wake_word_) {
                wake_word_->FeedAudioData(audio_frame.data(), audio_frame.size());
            }
        }
        else if (is_audio_processor_running) {
            // For general audio processing, pass to audio processor
            if (audio_processor_) {
                audio_processor_->ProcessAudio(std::move(audio_frame));
            }
        }
        else {
            // Default case - process through audio processor for basic functionality
            if (audio_processor_) {
                audio_processor_->ProcessAudio(std::move(audio_frame));
            }
        }

        // Small delay to prevent excessive CPU usage
        vTaskDelay(pdMS_TO_TICKS(1));
    }

    ESP_LOGW(TAG, "Audio input task stopped");
}

