void AudioService::OpusCodecTask() {
    while (true) {
        // Wait for either encode or decode tasks
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);

        // Wait until there's work in either queue
        audio_queue_cv_.wait(lock, [this]() { 
            return !audio_encode_queue_.empty() || 
                   !audio_decode_queue_.empty() || 
                   service_stopped_; 
        });

        if (service_stopped_) {
            break;
        }

        // Process encode queue (PCM -> Opus)
        while (!audio_encode_queue_.empty()) {
            auto task = std::move(audio_encode_queue_.front());
            audio_encode_queue_.pop_front();

            // Only process if we have valid PCM data
            if (task->pcm.empty()) {
                continue;
            }

            // Encode PCM to Opus
            std::vector<uint8_t> encoded_data;
            int encoded_length = opus_encoder_->Encode(task->pcm.data(), task->pcm.size(), encoded_data);

            if (encoded_length > 0) {
                // Create packet for sending
                auto packet = std::make_unique<AudioStreamPacket>();
                packet->payload = std::move(encoded_data);
                packet->sample_rate = 16000;  // Standard Opus sample rate
                packet->frame_duration = OPUS_FRAME_DURATION_MS;

                // Handle different task types
                if (task->type == kAudioTaskTypeEncodeToSendQueue) {
                    // Push to send queue for server transmission
                    if (audio_send_queue_.size() < MAX_SEND_PACKETS_IN_QUEUE) {
                        audio_send_queue_.push_back(std::move(packet));
                        audio_queue_cv_.notify_all();

                        // Signal that send queue has available data
                        if (callbacks_.on_send_queue_available) {
                            callbacks_.on_send_queue_available();
                        }
                    } else {
                        ESP_LOGW(TAG, "Send queue is full, dropping packet");
                    }
                } else if (task->type == kAudioTaskTypeEncodeToTestingQueue) {
                    // Push to testing queue for audio testing
                    if (audio_testing_queue_.size() < AUDIO_TESTING_MAX_DURATION_MS / OPUS_FRAME_DURATION_MS) {
                        audio_testing_queue_.push_back(std::move(packet));
                        audio_queue_cv_.notify_all();
                    } else {
                        ESP_LOGW(TAG, "Audio testing queue is full");
                    }
                }
            } else {
                ESP_LOGE(TAG, "Opus encoding failed");
            }

            // Notify that we've processed a task
            audio_queue_cv_.notify_all();
        }

        // Process decode queue (Opus -> PCM)
        while (!audio_decode_queue_.empty()) {
            auto packet = std::move(audio_decode_queue_.front());
            audio_decode_queue_.pop_front();

            // Decode Opus to PCM
            std::vector<int16_t> decoded_pcm;
            int decoded_samples = opus_decoder_->Decode(packet->payload.data(), packet->payload.size(), decoded_pcm);

            if (decoded_samples > 0) {
                // Resample if necessary
                if (decoded_pcm.size() > 0) {
                    // Check if we need to resample to output sample rate
                    if (opus_decoder_->sample_rate() != codec_->output_sample_rate()) {
                        auto resampled_pcm = std::vector<int16_t>(output_resampler_.GetOutputSamples(decoded_samples));
                        output_resampler_.Process(decoded_pcm.data(), decoded_samples, resampled_pcm.data());
                        decoded_pcm = std::move(resampled_pcm);
                    }

                    // Create playback task
                    auto playback_task = std::make_unique<AudioTask>();
                    playback_task->type = kAudioTaskTypeDecodeToPlaybackQueue;
                    playback_task->pcm = std::move(decoded_pcm);
                    playback_task->timestamp = packet->timestamp;

                    // Add to playback queue
                    if (audio_playback_queue_.size() < MAX_PLAYBACK_TASKS_IN_QUEUE) {
                        audio_playback_queue_.push_back(std::move(playback_task));
                        audio_queue_cv_.notify_all();
                    } else {
                        ESP_LOGW(TAG, "Playback queue is full, dropping decoded audio");
                    }
                }
            } else {
                ESP_LOGE(TAG, "Opus decoding failed");
            }

            // Notify that we've processed a packet
            audio_queue_cv_.notify_all();
        }

        lock.unlock();

        // Small delay to prevent busy waiting
        vTaskDelay(pdMS_TO_TICKS(1));
    }

    ESP_LOGW(TAG, "Opus codec task stopped");
}

