void AudioService::EnableWakeWordDetection(bool enable) {
    ESP_LOGI(TAG, "%s wake word detection", enable ? "Enabling" : "Disabling");

    if (enable) {
        // Initialize wake word detection if not already done
        if (!wake_word_) {
            ESP_LOGE(TAG, "Wake word model not loaded, cannot enable wake word detection");
            return;
        }

        // Initialize the wake word detector if needed
        if (!wake_word_->IsInitialized()) {
            wake_word_->Initialize();
        }

        // Start the wake word detection
        wake_word_->Start();

        // Set the event flag to indicate wake word detection is running
        xEventGroupSetBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    } else {
        // Stop the wake word detection
        if (wake_word_) {
            wake_word_->Stop();
        }

        // Clear the event flag
        xEventGroupClearBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    }
}

