AudioDebugger::AudioDebugger() {
#if CONFIG_USE_AUDIO_DEBUGGER
    // Initialize socket
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, 0);
    if (udp_sockfd_ < 0) {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
        return;
    }

    // Parse server address from configuration
    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));
    udp_server_addr_.sin_family = AF_INET;

    // Extract IP address and port from CONFIG_AUDIO_DEBUG_UDP_SERVER
    // Format expected: "IP_ADDRESS:PORT" or "HOSTNAME:PORT"
    const char* server_config = CONFIG_AUDIO_DEBUG_UDP_SERVER;
    if (server_config == nullptr || strlen(server_config) == 0) {
        ESP_LOGE(TAG, "Invalid server configuration");
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    // Parse IP address and port
    std::string server_str(server_config);
    size_t colon_pos = server_str.find(':');
    if (colon_pos == std::string::npos) {
        ESP_LOGE(TAG, "Invalid server format, expected IP:PORT");
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    std::string ip_str = server_str.substr(0, colon_pos);
    std::string port_str = server_str.substr(colon_pos + 1);

    // Convert port string to integer
    int port = atoi(port_str.c_str());
    if (port <= 0 || port > 65535) {
        ESP_LOGE(TAG, "Invalid port number: %d", port);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    // Set up server address structure
    udp_server_addr_.sin_port = htons(port);

    // Parse IP address
    if (inet_aton(ip_str.c_str(), &udp_server_addr_.sin_addr) == 0) {
        ESP_LOGE(TAG, "Invalid IP address: %s", ip_str.c_str());
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    ESP_LOGI(TAG, "UDP socket initialized successfully to %s:%d", 
             ip_str.c_str(), port);
#endif
}

