bool AfeWakeWord::Initialize(AudioCodec* codec, srmodel_list_t* models_list) {
    if (codec == nullptr || models_list == nullptr) {
        ESP_LOGE(TAG, "Invalid codec or models_list pointer");
        return false;
    }

    codec_ = codec;
    models_ = models_list;

    // Configure the audio codec
    if (codec_->Configure() != ESP_OK) {
        ESP_LOGE(TAG, "Failed to configure audio codec");
        return false;
    }

    // Initialize the AFE interface
    afe_iface_ = esp_afe_sr_get_interface();
    if (afe_iface_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get AFE interface");
        return false;
    }

    // Initialize AFE data structure
    afe_data_ = afe_iface_->create(models_list, codec_);
    if (afe_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create AFE data");
        return false;
    }

    // Set up wake word models and names
    wake_words_.clear();
    for (int i = 0; i < models_list->model_num; i++) {
        wake_words_.push_back(models_list->model[i].name);
    }

    // Create and start the audio detection task
    const size_t stack_size = 4096 * 4;
    const UBaseType_t priority = 5;

    // Allocate stack space for the task
    StackType_t* task_stack = (StackType_t*)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM);
    if (task_stack == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate stack for audio detection task");
        return false;
    }

    // Allocate static task buffer
    StaticTask_t* task_buffer = (StaticTask_t*)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
    if (task_buffer == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate task buffer");
        heap_caps_free(task_stack);
        return false;
    }

    // Create the task using static allocation
    TaskHandle_t task_handle = xTaskCreateStatic(
        [](void* arg) {
            auto this_ = (AfeWakeWord*)arg;
            this_->AudioDetectionTask();
        },
        "afe_wake_word_task",
        stack_size,
        this,
        priority,
        task_stack,
        task_buffer
    );

    if (task_handle == nullptr) {
        ESP_LOGE(TAG, "Failed to create audio detection task");
        heap_caps_free(task_stack);
        heap_caps_free(task_buffer);
        return false;
    }

    ESP_LOGI(TAG, "AFE wake word initialization completed successfully");
    return true;
}

