void CustomWakeWord::ParseWakenetModelConfig() {
    // Read index.json from assets
    const char* json_data = get_asset_content("index.json");
    if (json_data == nullptr) {
        ESP_LOGE(TAG, "Failed to load index.json from assets");
        return;
    }

    // Parse JSON
    cJSON* root = cJSON_Parse(json_data);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return;
    }

    // Extract language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item != nullptr && cJSON_IsString(language_item)) {
        language_ = language_item->valuestring;
        ESP_LOGI(TAG, "Parsed language: %s", language_.c_str());
    }

    // Extract duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item != nullptr && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valuedouble;
        ESP_LOGI(TAG, "Parsed duration: %d", duration_);
    }

    // Extract threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item != nullptr && cJSON_IsNumber(threshold_item)) {
        threshold_ = threshold_item->valuedouble;
        ESP_LOGI(TAG, "Parsed threshold: %f", threshold_);
    }

    // Extract commands
    cJSON* commands_item = cJSON_GetObjectItem(root, "commands");
    if (commands_item != nullptr && cJSON_IsArray(commands_item)) {
        int num_commands = cJSON_GetArraySize(commands_item);
        ESP_LOGI(TAG, "Found %d commands", num_commands);

        commands_.clear(); // Clear existing commands

        for (int i = 0; i < num_commands; i++) {
            cJSON* command_obj = cJSON_GetArrayItem(commands_item, i);
            if (command_obj == nullptr) continue;

            Command cmd;

            // Extract command name
            cJSON* command_name = cJSON_GetObjectItem(command_obj, "command");
            if (command_name != nullptr && cJSON_IsString(command_name)) {
                cmd.command = command_name->valuestring;
            }

            // Extract display text
            cJSON* display_text = cJSON_GetObjectItem(command_obj, "text");
            if (display_text != nullptr && cJSON_IsString(display_text)) {
                cmd.text = display_text->valuestring;
            }

            // Extract action
            cJSON* action = cJSON_GetObjectItem(command_obj, "action");
            if (action != nullptr && cJSON_IsString(action)) {
                cmd.action = action->valuestring;
            }

            // Add to commands list
            commands_.push_back(cmd);

            // Log the parsed command
            ESP_LOGI(TAG, "Parsed command %d: command='%s', text='%s', action='%s'", 
                     i + 1, cmd.command.c_str(), cmd.text.c_str(), cmd.action.c_str());
        }
    }

    // Clean up
    cJSON_Delete(root);
}

