void CustomWakeWord::Feed(const std::vector<int16_t> &data)
{
    if (!running_ || multinet_model_data_ == nullptr) {
        return;
    }

    // Process audio data - extract left channel if stereo
    std::vector<int16_t> processed_data = data;

    // If we have stereo data (channel count > 1), extract left channel
    // Note: This assumes the data is interleaved stereo (L,R,L,R,...)
    // But looking at the existing code pattern, it seems like we're working 
    // with mono audio data already, as seen in the AfeWakeWord::AudioDetectionTask

    // Store the audio data for potential later use (voice recognition)
    StoreWakeWordData(processed_data);

    // Run wake word detection using multinet
    int result = multinet_->detect(multinet_model_data_, processed_data.data());

    // Check if wake word was detected
    if (result > 0) {
        // Wake word detected - get the command name
        const char* detected_command = esp_mn_commands_get(result - 1);

        if (detected_command != nullptr) {
            // Convert to string and call callback
            std::string wake_word(detected_command);
            last_detected_wake_word_ = wake_word;

            if (wake_word_detected_callback_) {
                wake_word_detected_callback_(wake_word);
            }

            // Stop processing until reactivated
            Stop();
        }
    }
}

