void CustomWakeWord::EncodeWakeWordData() {
    // Allocate memory for task stack if not already done
    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = static_cast<char*>(
            heap_caps_malloc(8192, MALLOC_CAP_DEFAULT | MALLOC_CAP_INTERNAL));
        if (wake_word_encode_task_stack_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate encode task stack");
            return;
        }
    }

    // Allocate memory for task buffer if not already done
    if (wake_word_encode_task_buffer_ == nullptr) {
        wake_word_encode_task_buffer_ = static_cast<uint8_t*>(
            heap_caps_malloc(1024, MALLOC_CAP_DEFAULT | MALLOC_CAP_INTERNAL));
        if (wake_word_encode_task_buffer_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate encode task buffer");
            return;
        }
    }

    // Create a lambda function to perform the actual encoding work
    auto encode_task_func = [](void* arg) {
        CustomWakeWord* instance = static_cast<CustomWakeWord*>(arg);

        // Create Opus encoder with low complexity settings
        OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
        if (encoder == nullptr) {
            ESP_LOGE(TAG, "Failed to create Opus encoder");
            vTaskDelete(NULL);
            return;
        }

        // Set encoder parameters for low complexity
        opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));
        opus_encoder_ctl(encoder, OPUS_SET_BITRATE(24000));

        // Get PCM data from storage
        std::deque<std::vector<int16_t>> pcm_segments;
        {
            std::lock_guard<std::mutex> lock(instance->wake_word_mutex_);
            pcm_segments = instance->wake_word_pcm_;
        }

        // Encode each PCM segment
        for (const auto& segment : pcm_segments) {
            if (segment.empty()) continue;

            // Encode to Opus
            uint8_t opus_buffer[1024];
            int bytes_encoded = opus_encode(encoder, 
                                           segment.data(), 
                                           segment.size(), 
                                           opus_buffer, 
                                           sizeof(opus_buffer));

            if (bytes_encoded > 0) {
                // Add encoded data to queue
                std::vector<uint8_t> encoded_data(opus_buffer, opus_buffer + bytes_encoded);

                std::lock_guard<std::mutex> lock(instance->wake_word_mutex_);
                instance->wake_word_opus_.push_back(encoded_data);
            }
        }

        // Add termination marker
        std::vector<uint8_t> termination_marker = {0xFF, 0xFF, 0xFF, 0xFF};
        {
            std::lock_guard<std::mutex> lock(instance->wake_word_mutex_);
            instance->wake_word_opus_.push_back(termination_marker);
        }

        // Signal that data is ready
        instance->wake_word_cv_.notify_all();

        // Cleanup
        opus_encoder_destroy(encoder);
        vTaskDelete(NULL);
    };

    // Launch the encoding task
    BaseType_t result = xTaskCreatePinnedToCore((TaskFunction_t)encode_task_func,
                                               "encode_wake_word",
                                               8192,
                                               this,
                                               5,
                                               &wake_word_encode_task_handle_,
                                               1);

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create encode task");
    }
}

