void InitializeCamera() {
    // Power up the camera module
    // According to the board design, camera power is controlled via XL9555 pin 8
    xl9555_->SetOutputState(8, 1);

    // Add delay for power stabilization
    esp_rom_delay_us(10000); // 10ms delay

    // Reset the camera module
    // Reset signal is controlled via XL9555 pin 2
    xl9555_->SetOutputState(2, 0);  // Assert reset
    esp_rom_delay_us(1000);         // 1ms delay

    xl9555_->SetOutputState(2, 1);  // Deassert reset
    esp_rom_delay_us(10000);        // 10ms delay

