    camera_config.dvp->pin_d7 = GPIO_NUM_11;

    // Set up SCCB/I2C interface
    camera_config.sccb = new esp_video_sccb_config_t();
    camera_config.sccb->i2c_port = I2C_NUM_0;
    camera_config.sccb->sda_io_num = GPIO_NUM_39;
    camera_config.sccb->scl_io_num = GPIO_NUM_38;
    camera_config.sccb->clk_speed_hz = 100000;

    // Initialize the camera
    camera_ = new Esp32Camera(camera_config);

