std::string Board::GenerateUuid() {
    // Generate 16 bytes of random data
    uint8_t uuid_bytes[16];
    for (int i = 0; i < 16; i++) {
        uuid_bytes[i] = esp_random() & 0xFF;
    }

    // Set UUID version (4) in the 7th byte (bits 4-7 of the 7th byte)
    uuid_bytes[6] = (uuid_bytes[6] & 0xF0) | 0x40;

    // Set UUID variant (RFC 4122) in the 9th byte (bits 6-7 of the 9th byte)
    uuid_bytes[8] = (uuid_bytes[8] & 0x3F) | 0x80;

    // Format as string with hyphens
    char uuid_str[37]; // 36 characters + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid_bytes[0], uuid_bytes[1], uuid_bytes[2], uuid_bytes[3],
             uuid_bytes[4], uuid_bytes[5],
             uuid_bytes[6], uuid_bytes[7],
             uuid_bytes[8], uuid_bytes[9],
             uuid_bytes[10], uuid_bytes[11], uuid_bytes[12], uuid_bytes[13], uuid_bytes[14], uuid_bytes[15]);

    return std::string(uuid_str);
}

