void WifiBoard::StartNetwork()
{
    // Initialize WiFi manager with predefined SSID prefix and language
    auto &wifi_manager = WifiManager::GetInstance();

    // Set up unified event callback to handle various WiFi events
    wifi_manager.SetEventCallback([this](WifiEvent event, const std::string &data) {
        switch (event) {
            case WifiEvent::Scanning:
                ESP_LOGI(TAG, "WiFi scanning");
                break;
            case WifiEvent::Connecting:
                ESP_LOGI(TAG, "WiFi connecting to %s", data.c_str());
                break;
            case WifiEvent::Connected:
                ESP_LOGI(TAG, "Connected to WiFi: %s", data.c_str());
                // Stop timeout timer
                esp_timer_stop(connect_timer_);
#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
                // make sure blufi resources has been released
                Blufi::GetInstance().deinit();
#endif
                in_config_mode_ = false;
                // Notify external callback if set
                if (network_event_callback_) {
                    network_event_callback_(NetworkEvent::Connected, data);
                }
                break;
            case WifiEvent::Disconnected:
                ESP_LOGW(TAG, "WiFi disconnected");
                // Notify external callback if set
                if (network_event_callback_) {
                    network_event_callback_(NetworkEvent::Disconnected, data);
                }
                break;
            case WifiEvent::ConfigModeEnter:
                ESP_LOGI(TAG, "WiFi config mode entered");
                in_config_mode_ = true;
                // Notify external callback if set
                if (network_event_callback_) {
                    network_event_callback_(NetworkEvent::WifiConfigModeEnter, data);
                }
                break;
            case WifiEvent::ConfigModeExit:
                ESP_LOGI(TAG, "WiFi config mode exited");
                in_config_mode_ = false;
                // Try to connect with the new credentials
                TryWifiConnect();
                // Notify external callback if set
                if (network_event_callback_) {
                    network_event_callback_(NetworkEvent::WifiConfigModeExit, data);
                }
                break;
            default:
                break;
        }
    });

    // Attempt to establish WiFi connection or enter configuration mode
    TryWifiConnect();
}

