std::string WifiBoard::GetDeviceStatusJson() {
    std::string json = "{";

    // Add audio speaker volume
    auto audio_codec = GetAudioCodec();
    if (audio_codec) {
        int volume = audio_codec->get_volume();
        json += "\"volume\":" + std::to_string(volume) + ",";
    } else {
        json += "\"volume\":0,";
    }

    // Add screen brightness and theme
    auto display = GetDisplay();
    if (display) {
        int brightness = display->get_brightness();
        json += "\"brightness\":" + std::to_string(brightness) + ",";

        // Theme information (assuming we can get theme name)
        // This would depend on how themes are managed in the display system
        json += "\"theme\":\"default\",";
    } else {
        json += "\"brightness\":0,\"theme\":\"default\",";
    }

    // Add battery level and charging state
    // Assuming there's a power management interface or similar
    json += "\"battery_level\":100,\"charging\":false,"; // Placeholder values

    // Add WiFi network details
    auto& wifi = WifiManager::GetInstance();
    if (!wifi.IsConfigMode()) {
        json += "\"ssid\":\"" + wifi.GetSsid() + "\",";
        json += "\"rssi\":" + std::to_string(wifi.GetRssi()) + ",";
        json += "\"channel\":" + std::to_string(wifi.GetChannel()) + ",";
        json += "\"ip\":\"" + wifi.GetIpAddress() + "\",";
    } else {
        json += "\"ssid\":\"\",\"rssi\":0,\"channel\":0,\"ip\":\"\",";
    }

    // Add chip temperature (assuming we have access to temperature sensor)
    // This would typically use ESP-IDF functions like esp_adc_cal_get_voltage
    // For now using a placeholder value
    json += "\"temperature\":25.0";

    // Remove trailing comma if present
    if (json.back() == ',') {
        json.pop_back();
    }

    json += "}";
    return json;
}

