        gif_controller_->Stop();
        gif_controller_.reset();
    }

    if (preview_timer_ != nullptr)
    {
        esp_timer_stop(preview_timer_);
        esp_timer_delete(preview_timer_);
    }

    if (preview_image_ != nullptr)
