void LcdDisplay::SetChatMessage(const char* role, const char* content) {
    DisplayLockGuard lock(this);

    // Handle empty messages
    if (content == nullptr || content[0] == '\0') {
        return;
    }

    // Hide AI logo when showing non-system messages
    if (role != nullptr && strcmp(role, "system") != 0) {
        if (emoji_label_ != nullptr) {
            lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
        }
        if (emoji_image_ != nullptr) {
            lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
        }
    }

    // Remove oldest messages if we've reached the limit
    uint32_t child_count = lv_obj_get_child_cnt(content_);
    if (child_count >= MAX_MESSAGES) {
        // Remove the first child (oldest message)
        lv_obj_t* first_child = lv_obj_get_child(content_, 0);
        if (first_child != nullptr) {
            lv_obj_del(first_child);
        }
    }

    // Create message bubble based on role
    lv_obj_t* message_container = nullptr;
    lv_obj_t* message_bubble = nullptr;

    // Determine message type and create appropriate UI elements
    if (role != nullptr && strcmp(role, "system") == 0) {
        // System message - full-width bubble
        message_container = lv_obj_create(content_);
        lv_obj_set_style_radius(message_container, 0, 0);
        lv_obj_set_style_bg_opa(message_container, LV_OPA_TRANSP, 0);
        lv_obj_set_style_border_width(message_container, 0, 0);
        lv_obj_set_style_pad_all(message_container, 0, 0);
        lv_obj_set_style_flex_grow(message_container, 0, 0);

        message_bubble = lv_obj_create(message_container);
        lv_obj_set_style_radius(message_bubble, 8, 0);
        lv_obj_set_style_bg_color(message_bubble, current_theme_->system_bubble_color(), 0);
        lv_obj_set_style_bg_opa(message_bubble, LV_OPA_70, 0);
        lv_obj_set_style_border_width(message_bubble, 0, 0);
        lv_obj_set_style_pad_all(message_bubble, 8, 0);
        lv_obj_set_style_flex_grow(message_bubble, 1, 0);
        lv_obj_set_style_width(message_bubble, LV_PCT(100), 0);

        // Mark as system bubble for theme updates
        lv_obj_set_user_data(message_bubble, (void*)"system");

        // Add label inside bubble
        lv_obj_t* message_label = lv_label_create(message_bubble);
        lv_label_set_text(message_label, content);
        lv_obj_set_style_text_color(message_label, current_theme_->system_text_color(), 0);
        lv_obj_set_style_text_align(message_label, LV_TEXT_ALIGN_CENTER, 0);
        lv_label_set_long_mode(message_label, LV_LABEL_LONG_WRAP);
        lv_obj_set_width(message_label, LV_PCT(100));
        lv_obj_set_style_text_line_space(message_label, 4, 0);

    } else {
        // User or assistant message - left/right aligned bubbles
        bool is_user_message = (role != nullptr && strcmp(role, "user") == 0);

        message_container = lv_obj_create(content_);
        lv_obj_set_style_radius(message_container, 0, 0);
        lv_obj_set_style_bg_opa(message_container, LV_OPA_TRANSP, 0);
        lv_obj_set_style_border_width(message_container, 0, 0);
        lv_obj_set_style_pad_all(message_container, 0, 0);
        lv_obj_set_style_flex_grow(message_container, 0, 0);

        // Set alignment based on role
        if (is_user_message) {
            lv_obj_align(message_container, LV_ALIGN_LEFT_MID, 0, 0);
        } else {
            lv_obj_align(message_container, LV_ALIGN_RIGHT_MID, 0, 0);
        }

        message_bubble = lv_obj_create(message_container);
        lv_obj_set_style_radius(message_bubble, 8, 0);
        lv_obj_set_style_border_width(message_bubble, 0, 0);
        lv_obj_set_style_pad_all(message_bubble, 8, 0);
        lv_obj_set_style_flex_grow(message_bubble, 1, 0);

        // Set bubble color based on role
        if (is_user_message) {
            lv_obj_set_style_bg_color(message_bubble, current_theme_->user_bubble_color(), 0);
            lv_obj_set_user_data(message_bubble, (void*)"user");
        } else {
            lv_obj_set_style_bg_color(message_bubble, current_theme_->assistant_bubble_color(), 0);
            lv_obj_set_user_data(message_bubble, (void*)"assistant");
        }

        // Add label inside bubble
        lv_obj_t* message_label = lv_label_create(message_bubble);
        lv_label_set_text(message_label, content);
        lv_obj_set_style_text_color(message_label, current_theme_->text_color(), 0);
        lv_obj_set_style_text_align(message_label, LV_TEXT_ALIGN_LEFT, 0);
        lv_label_set_long_mode(message_label, LV_LABEL_LONG_WRAP);

        // Limit bubble width to 80% of screen
        lv_coord_t max_width = LV_HOR_RES * 80 / 100;
        lv_obj_set_width(message_bubble, max_width);
    }

    // Add scroll to view for new messages
    lv_obj_scroll_to_view_recursive(message_container, LV_ANIM_ON);
}

