void LcdDisplay::SetPreviewImage(std::unique_ptr<LvglImage> image) {
    DisplayLockGuard lock(this);

    if (preview_image_ == nullptr) {
        ESP_LOGE(TAG, "Preview image is not initialized");
        return;
    }

    if (image == nullptr) {
        esp_timer_stop(preview_timer_);
        lv_obj_remove_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
        lv_obj_add_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);
        preview_image_cached_.reset();
        if (gif_controller_) {
            gif_controller_->Start();
        }
        return;
    }

    preview_image_cached_ = std::move(image);
    auto img_dsc = preview_image_cached_->image_dsc();
    lv_image_set_src(preview_image_, img_dsc);

    // Handle invalid image dimensions
    if (img_dsc->header.w <= 0 || img_dsc->header.h <= 0) {
        ESP_LOGW(TAG, "Invalid image dimensions: %dx%d", img_dsc->header.w, img_dsc->header.h);
        // Use default sizing
        lv_image_set_scale(preview_image_, 128); // Default scale
    } else {
        // Calculate scale to fit within maximum dimensions
        const int max_width = width_ * 3 / 4;  // 75% of screen width
        const int max_height = height_ * 3 / 4;  // 75% of screen height

        int scale_w = (max_width * 256) / img_dsc->header.w;
        int scale_h = (max_height * 256) / img_dsc->header.h;

        // Use the smaller scale to ensure the image fits within both dimensions
        int scale = std::min(scale_w, scale_h);

        // Ensure minimum scale to prevent overly small images
        if (scale < 64) {  // Minimum 25% scale
            scale = 64;
        }

        lv_image_set_scale(preview_image_, scale);
    }

    // Hide emoji_box_
    if (gif_controller_) {
        gif_controller_->Stop();
    }
    lv_obj_add_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
    lv_obj_remove_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);
    esp_timer_stop(preview_timer_);
    ESP_ERROR_CHECK(esp_timer_start_once(preview_timer_, PREVIEW_IMAGE_DURATION_MS * 1000));
}

