    esp_err_t ret = led_strip_new_rmt_device(&led_strip_cfg, &led_strip_);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create LED strip: %s", esp_err_to_name(ret));
        return;
    }

    // Initialize blink timer
    const esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            SingleLed* led = static_cast<SingleLed*>(arg);
            led->OnBlinkTimer();
        },
        .name = "led_blink",
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
        .alarm_rate_hz = 1000  // 1kHz timer rate
    };

    ret = esp_timer_create(&timer_args, &blink_timer_);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create blink timer: %s", esp_err_to_name(ret));
        led_strip_del(led_strip_);
        led_strip_ = nullptr;
        return;
    }

    // Clear LED initially (turn off)
    led_strip_clear(led_strip_);

    // Initialize color to off state
    r_ = 0;
    g_ = 0;
    b_ = 0;
}

