bool MqttProtocol::StartMqttClient(bool report_error) {
    // Check if we're already alive
    if (!*alive_) {
        ESP_LOGW(TAG, "MQTT client is not alive, cannot start");
        return false;
    }

    // Reset previous MQTT connection
    mqtt_.reset();

    // Get configuration from settings
    auto& settings = Settings::GetInstance();
    std::string broker_url = settings.GetMqttBrokerUrl();
    std::string client_id = settings.GetClientId();
    std::string username = settings.GetMqttUsername();
    std::string password = settings.GetMqttPassword();
    std::string subscribe_topic = settings.GetMqttSubscribeTopic();
    publish_topic_ = settings.GetMqttPublishTopic();

    // Validate configuration
    if (broker_url.empty() || client_id.empty()) {
        ESP_LOGE(TAG, "MQTT configuration incomplete");
        if (report_error) {
            SetError(Lang::Strings::MQTT_CONFIG_ERROR);
        }
        return false;
    }

    // Create MQTT client
    mqtt_ = std::make_unique<Mqtt>(client_id);

    // Set up MQTT connection parameters
    mqtt_->SetBroker(broker_url);
    mqtt_->SetUsername(username);
    mqtt_->SetPassword(password);

    // Set up event handlers
    mqtt_->OnConnected([this]() {
        ESP_LOGI(TAG, "MQTT connected successfully");

        // Subscribe to topic
        if (!publish_topic_.empty()) {
            mqtt_->Subscribe(publish_topic_);
        }

        // Schedule reconnect timer to keep connection alive
        esp_timer_start_periodic(reconnect_timer_, MQTT_PING_INTERVAL_SECONDS * 1000000);

        // Trigger connected callback
        if (on_connected_ != nullptr) {
            on_connected_();
        }
    });

    mqtt_->OnDisconnected([this]() {
        ESP_LOGW(TAG, "MQTT disconnected");

        // Stop reconnect timer
        esp_timer_stop(reconnect_timer_);

        // Trigger disconnected callback
        if (on_disconnected_ != nullptr) {
            on_disconnected_();
        }

        // Schedule reconnection attempt if still alive
        if (*alive_) {
            ESP_LOGI(TAG, "Scheduling MQTT reconnect in %d ms", MQTT_RECONNECT_INTERVAL_MS);
            esp_timer_start_once(reconnect_timer_, MQTT_RECONNECT_INTERVAL_MS * 1000);
        }
    });

    mqtt_->OnMessage([this](const std::string& topic, const std::string& payload) {
        ESP_LOGI(TAG, "MQTT message received on topic: %s", topic.c_str());

        // Parse JSON payload
        cJSON* root = cJSON_Parse(payload.c_str());
        if (root == nullptr) {
            ESP_LOGE(TAG, "Failed to parse JSON payload: %s", payload.c_str());
            return;
        }

        // Process different message types
        auto type = cJSON_GetObjectItem(root, "type");
        if (type != nullptr && cJSON_IsString(type)) {
            if (strcmp(type->valuestring, "hello") == 0) {
                ParseServerHello(root);
            } else if (strcmp(type->valuestring, "server_hello") == 0) {
                ParseServerHello(root);
            } else {
                // Forward to application layer for processing
                if (on_incoming_json_ != nullptr) {
                    on_incoming_json_(root);
                }
            }
        } else {
            // Forward to application layer for processing
            if (on_incoming_json_ != nullptr) {
                on_incoming_json_(root);
            }
        }

        cJSON_Delete(root);
    });

    // Attempt to connect
    ESP_LOGI(TAG, "Connecting to MQTT broker: %s", broker_url.c_str());
    if (!mqtt_->Connect()) {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        if (report_error) {
            SetError(Lang::Strings::MQTT_CONNECT_ERROR);
        }
        return false;
    }

    return true;
}

