{
    if (udp_ == nullptr) {
        ESP_LOGE(TAG, "UDP channel is not opened");
        return false;
    }

    // Thread-safe access to UDP channel
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Prepare the nonce - combine aes_nonce_ with packet info
    // Format: [aes_nonce_] + [payload_size:2bytes] + [timestamp:4bytes] + [sequence:4bytes]
    std::string nonce = aes_nonce_;

    // Add packet size (2 bytes, big-endian)
    uint16_t payload_size = static_cast<uint16_t>(packet->payload.size());
    nonce.push_back(static_cast<char>((payload_size >> 8) & 0xFF));
    nonce.push_back(static_cast<char>(payload_size & 0xFF));

    // Add timestamp (4 bytes, big-endian)
    uint32_t timestamp = htonl(packet->timestamp);
    nonce.push_back(static_cast<char>((timestamp >> 24) & 0xFF));
    nonce.push_back(static_cast<char>((timestamp >> 16) & 0xFF));
    nonce.push_back(static_cast<char>((timestamp >> 8) & 0xFF));
    nonce.push_back(static_cast<char>(timestamp & 0xFF));

    // Add sequence number (4 bytes, big-endian)
    uint32_t sequence = htonl(local_sequence_);
    nonce.push_back(static_cast<char>((sequence >> 24) & 0xFF));
    nonce.push_back(static_cast<char>((sequence >> 16) & 0xFF));
    nonce.push_back(static_cast<char>((sequence >> 8) & 0xFF));
    nonce.push_back(static_cast<char>(sequence & 0xFF));

    // Increment sequence number for next packet
    local_sequence_++;

    // Encrypt the payload using AES-CTR
    std::string encrypted_data;
    encrypted_data.resize(1 + 1 + 2 + 4 + 4 + packet->payload.size()); // type + flags + payload_len + ssrc + timestamp + sequence + payload

    // Set packet header fields
    encrypted_data[0] = 0x01; // type
    encrypted_data[1] = 0x00; // flags
    // payload_len (2 bytes, big-endian)
    uint16_t payload_len = packet->payload.size();
    encrypted_data[2] = static_cast<char>((payload_len >> 8) & 0xFF);
    encrypted_data[3] = static_cast<char>(payload_len & 0xFF);
    // ssrc (4 bytes, zero for now)
    encrypted_data[4] = 0x00;
    encrypted_data[5] = 0x00;
    encrypted_data[6] = 0x00;
    encrypted_data[7] = 0x00;
    // timestamp (4 bytes, big-endian)
    uint32_t ts = htonl(packet->timestamp);
    encrypted_data[8] = static_cast<char>((ts >> 24) & 0xFF);
    encrypted_data[9] = static_cast<char>((ts >> 16) & 0xFF);
    encrypted_data[10] = static_cast<char>((ts >> 8) & 0xFF);
    encrypted_data[11] = static_cast<char>(ts & 0xFF);
    // sequence (4 bytes, big-endian)
    uint32_t seq = htonl(local_sequence_ - 1);
    encrypted_data[12] = static_cast<char>((seq >> 24) & 0xFF);
    encrypted_data[13] = static_cast<char>((seq >> 16) & 0xFF);
    encrypted_data[14] = static_cast<char>((seq >> 8) & 0xFF);
    encrypted_data[15] = static_cast<char>(seq & 0xFF);

    // Copy the encrypted payload after the header
    memcpy(encrypted_data.data() + 16, packet->payload.data(), packet->payload.size());

    // Encrypt the payload part (after header) using AES-CTR
    size_t encrypted_size = packet->payload.size();
    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};

    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, 
                                   encrypted_size, 
                                   &nc_off, 
                                   (const unsigned char*)nonce.data(), 
                                   stream_block, 
                                   (const unsigned char*)(packet->payload.data()), 
                                   (unsigned char*)(encrypted_data.data() + 16));

    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        return false;
    }

    // Send the encrypted packet over UDP
    if (!udp_->Send(encrypted_data)) {
        ESP_LOGE(TAG, "Failed to send audio packet over UDP");
        return false;
    }

    return true;
}

