void MqttProtocol::ParseServerHello(const cJSON* root) {
    // Extract server address and port for UDP connection
    auto server = cJSON_GetObjectItem(root, "server");
    if (server != nullptr && cJSON_IsString(server)) {
        udp_server_ = server->valuestring;
        ESP_LOGI(TAG, "UDP server: %s", udp_server_.c_str());
    }

    auto port = cJSON_GetObjectItem(root, "port");
    if (port != nullptr && cJSON_IsNumber(port)) {
        udp_port_ = port->valueint;
        ESP_LOGI(TAG, "UDP port: %d", udp_port_);
    }

    // Extract encryption key and nonce
    auto key = cJSON_GetObjectItem(root, "key");
    if (key != nullptr && cJSON_IsString(key)) {
        std::string key_hex = key->valuestring;
        std::string key_data = DecodeHexString(key_hex);
        if (key_data.size() == 16) {  // AES-128 key
            mbedtls_aes_setkey_enc(&aes_ctx_, (const unsigned char*)key_data.data(), 128);
            ESP_LOGI(TAG, "AES key set");
        }
    }

    auto nonce = cJSON_GetObjectItem(root, "nonce");
    if (nonce != nullptr && cJSON_IsString(nonce)) {
        std::string nonce_hex = nonce->valuestring;
        aes_nonce_ = DecodeHexString(nonce_hex);
        if (aes_nonce_.size() == 16) {
            ESP_LOGI(TAG, "AES nonce set");
        }
    }

    // Extract session ID
    auto session_id = cJSON_GetObjectItem(root, "session_id");
    if (cJSON_IsString(session_id)) {
        session_id_ = session_id->valuestring;
        ESP_LOGI(TAG, "Session ID: %s", session_id_.c_str());
    }

    // Extract audio parameters
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (cJSON_IsObject(audio_params)) {
        auto sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (cJSON_IsNumber(sample_rate)) {
            server_sample_rate_ = sample_rate->valueint;
            ESP_LOGI(TAG, "Server sample rate: %d", server_sample_rate_);
        }

        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valueint;
            ESP_LOGI(TAG, "Server frame duration: %d", server_frame_duration_);
        }
    }

    // Signal that server hello has been processed
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

